                        background: 'rgba(0, 0, 0, 0.60)',
                        backdropFilter: 'blur(40px)',
                        WebkitBackdropFilter: 'blur(40px)',
                        borderLeft: '1px solid rgba(249,115,22,0.20)',
                        boxShadow: '-12px 0 60px rgba(0,0,0,0.6), 0 0 40px rgba(249,115,22,0.06)',
